function normalizeLegacyCompactReturn(raw: Record<string, unknown>, activeChild: string): Record<string, unknown> {
  const result = { ...raw };

  if (typeof result['child_id'] !== 'string' || !result['child_id']) {
    result['child_id'] = activeChild;
  }

  if (result['status'] === 'success' || result['status'] === 'completed') {
    result['status'] = 'done';
  } else if (result['status'] === 'failure' || result['status'] === 'error' || result['status'] === 'in-progress') {
    result['status'] = 'failed';
  } else if (result['status'] !== 'done' && result['status'] !== 'failed' && result['status'] !== 'blocked') {
    // Unknown or missing status is treated as a failure signal rather than an
    // optimistic success, forcing the sealed result down the review path.
    result['status'] = 'failed';
  }
